def perceive(data):
    text = data if isinstance(data, str) else (
        data.get("text", "") if isinstance(data, dict) else str(data))
    fields = {}
    for line in text.splitlines():
        if ":" not in line:
            continue
        key, _, value = line.partition(":")
        key = key.strip().lower()
        value = value.strip()
        if key in ("rule", "requested_by", "risk"):
            fields[key] = value
    out = {}
    if "rule" in fields:
        out["pending_rule"] = fields["rule"]
    if "requested_by" in fields:
        out["requested_by"] = fields["requested_by"]
    if "risk" in fields:
        out["risk"] = fields["risk"]
    return out
